import Header from "../components/Header";
import Footer from "../components/Footer";
import BtnPostuler from "../components/BtnPostuler";
import "../styles/AddOffer.css";
import { useState } from "react";

const AddOffer = () => {
  const [intitule, setIntitule] = useState("");
  const [typeContrat, setTypeContrat] = useState("");
  const [dureeContrat, setDureeContrat] = useState("");
  const [lieuMission, setLieuMission] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

  const offre = {
    intitule,
    typeContrat,
    dureeContrat,
    lieuMission,
  };

    try {
    const response = await fetch('http://localhost:5000/api/offers', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(offre),
    });

    if (!response.ok) {
      const errorData = await response.json();
      alert(errorData.error || "Erreur lors de l'enregistrement.");
      return;
    }

    // Optionnel : réinitialiser le formulaire
    setIntitule("");
    setTypeContrat("");
    setDureeContrat("");
    setLieuMission("");

    alert("Offre enregistrée avec succès !");
  } catch (error) {
    alert("Erreur lors de l'enregistrement.");
  }
  };

  return (
    <div>
      <Header />
      <main>
        <h1>Ajout d'une offre</h1>
        <section>
          <form onSubmit={handleSubmit}>
            <div>
              <h3>Intitulé du poste</h3>
              {/* <input v-model="intitule" type="text" placeholder = "Veuillez saisir l'intitulé du poste"></input> */}
              <input
                value={intitule}
                onChange={(e) => setIntitule(e.target.value)}
                type="text"
                placeholder="Veuillez saisir l'intitulé du poste"
              />
            </div>
            <div>
              <h3>Type de contrat</h3>
              {/* <input v-model="typeContrat" type="text" placeholder = "Veuillez saisir le type de contrat"></input> */}
              <input
                value={typeContrat}
                onChange={(e) => setTypeContrat(e.target.value)}
                type="text"
                placeholder="Veuillez saisir le type de contrat"
              />
            </div>
            <div>
              <h3>Durée du contrat</h3>
              {/* <input v-model="dureeContrat" type="text" placeholder = "Veuillez saisir la durée du contrat"></input> */}
              <input
                value={dureeContrat}
                onChange={(e) => setDureeContrat(e.target.value)}
                type="text"
                placeholder="Veuillez saisir la durée du contrat"
              />
            </div>
            <div>
              <h3>Lieu</h3>
              {/* <input v-model="lieuMission" type="text" placeholder = "Veuillez saisir le lieu de la mission"></input> */}
              <input
                value={lieuMission}
                onChange={(e) => setLieuMission(e.target.value)}
                type="text"
                placeholder="Veuillez saisir le lieu de la mission"
              />
            </div>
            {/* <button type="submit">Ajouter l'offre</button> */}
            <BtnPostuler type="submit">Ajouter l'offre</BtnPostuler>
          </form>
        </section>
      </main>
      <Footer />
    </div>
  );
};

export default AddOffer;
